svg.script:
  var text = document.getElementById('animated-number');
  var current = 1;
  function animateNumbers() {
if (current <= 30) {
      text.textContent = current;
      current++;
      setTimeout(animateNumbers, 150);
    } else {
      setTimeout(function() {
        current = 1;
        setTimeout(animateNumbers, 2000); // تأخير 2 ثانية قبل إعادة العد
      }, 5000);
    }
  }
  setTimeout(animateNumbers, 2000); // تأخير أولي 2 ثانية قبل بدء العد
